const d = $input.item.json.body;

// Hàm format số tiền thành chuẩn VN (VD: 3.500.000), không tự thêm chữ "đ" vì trong HTML đã tự gõ "đ/tháng"
const fmt = (n) => {
    if (!n) return '....................';
    return new Intl.NumberFormat('vi-VN').format(n);
};

d.giaThueFormatted = fmt(d.giaThue);
d.tienCocFormatted = fmt(d.tienCoc);

// Lấy ngày tháng năm hiện tại chia ra từng biến để in vào hợp đồng
const today = new Date();
const day = String(today.getDate()).padStart(2, '0');
const month = String(today.getMonth() + 1).padStart(2, '0');
const year = today.getFullYear();

d.soThangText = (d.soThang || 12) + ' tháng';

// Khung HTML chuẩn MS Word (Font Times New Roman, dãn dòng 1.5)
d.htmlContract = `<!DOCTYPE html>
<html lang="vi">
<head>
<meta charset="UTF-8">
<style>
  body { 
    font-family: "Times New Roman", Times, serif; 
    font-size: 14pt; 
    line-height: 1.5; 
    margin: 40px; /* Căn lề như giấy A4 */
    color: #000; 
  }
  .center { text-align: center; }
  .bold { font-weight: bold; }
  .italic { font-style: italic; }
  .uppercase { text-transform: uppercase; }
  .justify { text-align: justify; }
  h1 { font-size: 14pt; margin: 5px 0; }
  h2 { font-size: 16pt; margin: 20px 0; }
  p { margin: 5px 0; text-align: justify; }
  .indent { padding-left: 20px; }
  .signatures { display: flex; justify-content: space-between; margin-top: 30px; }
  .sig-box { width: 45%; text-align: center; }
  .spacing-bottom { margin-bottom: 90px; }
  .dotted-line { display: inline-block; border-bottom: 1px dotted #000; min-width: 150px; }
</style>
</head>
<body>
  <div class="center bold">
    <h1 class="uppercase">CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</h1>
    <p>Độc lập – Tự do – Hạnh phúc</p>
    <p>---o0o---</p>
  </div>

  <h2 class="center bold uppercase">HỢP ĐỒNG THUÊ PHÒNG TRỌ</h2>

  <p class="italic center">Hôm nay, ngày ${day} tháng ${month} năm ${year}; tại địa chỉ: ................................................................</p>
  <p>Chúng tôi gồm:</p>

  <p class="bold">1. Đại diện bên cho thuê phòng trọ (Bên A):</p>
  <div class="indent">
      <p>Ông/bà: <b>Huỳnh Ngọc Huy</b> <span style="float:right">Sinh ngày: ....................................</span></p>
      <p>Nơi đăng ký HK: ..............................................................................................................................</p>
      <p>CMND/CCCD số: .................................... cấp ngày .......................... tại: ....................................</p>
      <p>Số điện thoại: ................................................</p>
  </div>

  <p class="bold">2. Bên thuê phòng trọ (Bên B):</p>
  <div class="indent">
      <p>Ông/bà: <b>${d.hoTen || '........................................'}</b> <span style="float:right">Sinh ngày: ${d.ngaySinh || '....................................'}</span></p>
      <p>Nơi đăng ký HK thường trú: ${d.thuongTru || '...................................................................................................'}</p>
      <p>Số CMND/CCCD: <b>${d.soCccd || '....................................'}</b> cấp ngày: ${d.ngayCap || '....................'} tại: ${d.noiCap || '....................'}</p>
      <p>Số điện thoại: <b>${d.sdt || '................................................'}</b></p>
  </div>

  <p>Sau khi bàn bạc trên tinh thần dân chủ, hai bên cùng có lợi, cùng thống nhất như sau:</p>
  <p>Bên A đồng ý cho bên B thuê 01 phòng ở tại địa chỉ: ................................................................................</p>

  <div class="indent">
      <p>- Phòng số: <b>${d.phong || '...........'}</b></p>
      <p>- Giá thuê: <b>${d.giaThueFormatted} đ/tháng</b></p>
      <p>- Hình thức thanh toán: ....................................................................................................................</p>
      <p>- Tiền điện: 3.500 đ/kwh tính theo chỉ số công tơ, thanh toán vào cuối các tháng.</p>
      <p>- Tiền nước: 100.000 đ/người thanh toán vào đầu các tháng.</p>
      <p>- Tiền đặt cọc: <b>${d.tienCocFormatted} đ</b></p>
      <p>- Thời hạn thuê: <b>${d.soThangText}</b>, bắt đầu tính tiền từ ngày: <b>${d.ngayBatDau || '....................'}</b></p>
  </div>

  <p class="bold uppercase" style="margin-top: 15px; text-decoration: underline;">TRÁCH NHIỆM CỦA CÁC BÊN</p>

  <p class="bold">* Trách nhiệm của bên A:</p>
  <div class="indent">
      <p>- Tạo mọi điều kiện thuận lợi để bên B thực hiện theo hợp đồng.</p>
      <p>- Cung cấp nguồn điện, nước, wifi cho bên B sử dụng.</p>
  </div>

  <p class="bold">* Trách nhiệm của bên B:</p>
  <div class="indent">
      <p>- Thanh toán đầy đủ các khoản tiền theo đúng thỏa thuận.</p>
      <p>- Bảo quản các trang thiết bị và cơ sở vật chất của bên A trang bị cho ban đầu (làm hỏng phải sửa, mất phải đền).</p>
      <p>- Không được tự ý sửa chữa, cải tạo cơ sở vật chất khi chưa được sự đồng ý của bên A.</p>
      <p>- Giữ gìn vệ sinh trong và ngoài khuôn viên của phòng trọ.</p>
      <p>- Bên B phải chấp hành mọi quy định của pháp luật Nhà nước và quy định của địa phương.</p>
      <p>- Nếu bên B cho khách ở qua đêm thì phải báo và được sự đồng ý của chủ nhà đồng thời phải chịu trách nhiệm về các hành vi vi phạm pháp luật của khách trong thời gian ở lại.</p>
  </div>

  <p class="bold uppercase" style="margin-top: 15px; text-decoration: underline;">TRÁCH NHIỆM CHUNG</p>
  <div class="indent">
      <p>- Hai bên phải tạo điều kiện cho nhau thực hiện hợp đồng.</p>
      <p>- Trong thời gian hợp đồng còn hiệu lực nếu bên nào vi phạm các điều khoản đã thỏa thuận thì bên còn lại có quyền đơn phương chấm dứt hợp đồng; nếu sự vi phạm hợp đồng đó gây tổn thất cho bên bị vi phạm hợp đồng thì bên vi phạm hợp đồng phải bồi thường thiệt hại.</p>
      <p>- Một trong hai bên muốn chấm dứt hợp đồng trước thời hạn thì phải báo trước cho bên kia ít nhất 30 ngày và hai bên phải có sự thống nhất.</p>
      <p>- Bên A phải trả lại tiền đặt cọc cho bên B.</p>
      <p>- Bên nào vi phạm điều khoản chung thì phải chịu trách nhiệm trước pháp luật.</p>
      <p>- Hợp đồng được lập thành 02 bản có giá trị pháp lý như nhau, mỗi bên giữ một bản.</p>
  </div>

  <div class="signatures">
      <div class="sig-box">
          <p class="bold">ĐẠI DIỆN BÊN B</p>
          <p class="italic spacing-bottom">(Ký, ghi rõ họ tên)</p>
          <p class="bold">${d.hoTen || ''}</p>
      </div>
      <div class="sig-box">
          <p class="bold">ĐẠI DIỆN BÊN A</p>
          <p class="italic spacing-bottom">(Ký, ghi rõ họ tên)</p>
          <p class="bold">Huỳnh Ngọc Huy</p>
      </div>
  </div>
</body>
</html>`;

return d;

// Chuyển HTML string thành binary file index.html
// để Gotenberg nhận đúng format multipart
const htmlContent = $json.htmlContract;
const base64Html = Buffer.from(htmlContent, 'utf-8').toString('base64');

// Gắn vào binary data của item
$binary = {
  indexHtml: {
    data: base64Html,
    mimeType: 'text/html',
    fileName: 'index.html',
    fileExtension: 'html'
  }
};

return { json: $json, binary: $binary };

// Lấy chính xác cái key mà Gotenberg đã trả về (thường nó đang bị kẹt tên "indexHtml")
const binaryKey = Object.keys($input.item.binary)[0];

if (!binaryKey) {
  throw new Error("Không có file từ Gotenberg!");
}

// Giải mã Base64 cực mượt để đưa xuống DB
const fileBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const pdfBase64 = fileBuffer.toString('base64');

// Lấy lại dữ liệu cũ từ node Format và đưa vào JSON để gửi xuống Fastapi
const prevData = $('Format & Tạo HTML Hợp Đồng').item.json;
$input.item.json = {
  ...prevData,
  pdfBase64: pdfBase64
};

// 🎯 ĐÂY LÀ CHÌA KHÓA: Đổi tên key thành "data" để Node GMAIL nhận diện được file!
$input.item.binary = {
  data: $input.item.binary[binaryKey]
};

// Bonus: Đổi luôn tên file đính kèm thành dạng "Hop_Dong_Phong_A101.pdf" gửi khách cho ngầu
$input.item.binary.data.fileName = `Hop_Dong_Phong_${prevData.phong}.pdf`;
$input.item.binary.data.mimeType = 'application/pdf';

return $input.item;

